import{j as l,b as i,c as t,aa as e}from"./chunks/framework.Bxf40uRC.js";const g=JSON.parse('{"title":"Linux常用指令","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/linux常用指令.md","filePath":"Linux/linux常用指令.md","lastUpdated":null}'),o={name:"Linux/linux常用指令.md"},s=e('<h1 id="linux常用指令" tabindex="-1">Linux常用指令 <a class="header-anchor" href="#linux常用指令" aria-label="Permalink to &quot;Linux常用指令&quot;">​</a></h1><h2 id="网络监控" tabindex="-1">网络监控 <a class="header-anchor" href="#网络监控" aria-label="Permalink to &quot;网络监控&quot;">​</a></h2><ol><li><strong>netstat/ss -tunlp</strong> : t 表示tcp，u表示udp，l表示listen，n表示使用ip和端口展示，p展示pid</li><li><strong>iftop</strong>：监控网络带宽的使用情况</li><li><strong>ifconfig</strong>: 查看本地ip地址信息</li></ol><h2 id="系统管理" tabindex="-1">系统管理 <a class="header-anchor" href="#系统管理" aria-label="Permalink to &quot;系统管理&quot;">​</a></h2><ol><li><strong>top</strong> ：监控内存和cpu使用率的命令，过程中按P代表按照CPU使用率降序排序，M代表按照Memory降序排序</li><li><strong>systemctl</strong>：控制systemd系统和服务管理器。</li></ol><ul><li><p>启动服务：<code>systemctl start servicename</code></p></li><li><p>停止服务：<code>systemctl stop servicename</code></p></li><li><p>重启服务：<code>systemctl restart servicename</code></p></li><li><p>显示服务状态：<code>systemctl status servicename</code></p></li><li><p>开机自启：<code>systemctl enable servicename</code></p></li><li><p>禁止开机自启：<code>systemctl disable servicename</code></p></li></ul><ol start="3"><li><strong>ps</strong>：显示当前所有的进程 <ul><li>-e显示所有进程</li><li>-f表示全格式</li><li>a表示显示除控制进程（session leaders）和没有控制终端的进程外的所有进程</li><li>u表示用户为中心的格式输出，提供每个进程的用户名称，CPU和内存使用率等详细信息</li><li>x显示没有控制终端的进程，通常与进行一起使用</li></ul></li><li><strong>kill -9 pid</strong>: -9强制终止进程，不加的话就是终止进程</li><li><strong>killall</strong>：根据进程名终止所有进程</li><li><strong>jobs</strong>：列出当前会话中的所有任务，包括后台运行的进程。</li><li><strong>nice</strong>：优先级范围从-20（最高优先级）到19（最低优先级) <ul><li>nice -n 5 command：表示nice值 + 5启动command，通常越小，优先级越高</li></ul></li><li><strong>journalctl</strong> : 查看系统所有日志 <ul><li>-u 表示查看特定服务的日志</li><li>--since today 表示查看今天的日志</li><li>-f 滚动查看最新的日志</li><li>--since &quot;2021-01-30 14:00&quot; --until &quot;2021-01-30 16:00&quot; 查看某个时间段的日志</li></ul></li></ol><h2 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h2><ol><li><strong>pwd</strong>：显示当前文件目录</li><li><strong>mv</strong>： 可以进行文件命名操作，也可以进行文件移动操作</li></ol>',9),n=[s];function a(r,c,d,u,p,m){return i(),t("div",null,n)}const h=l(o,[["render",a]]);export{g as __pageData,h as default};
